// Entrada esperada desde GHL Workflow (acción Custom Webhook):
// { opportunityId, newStageId, locationId }
//
// También tolera el formato del sistema GHL (OpportunityStageUpdate):
// { id, pipelineStageId, locationId }
const body = $input.first().json.body || $input.first().json;

const opportunityId = body.opportunityId || body.id || '';
const newStageId    = body.newStageId
                   || body.pipelineStageId
                   || body.pipeline_stage_id
                   || body.stageId
                   || '';
const locationId    = body.locationId || body.location_id || '';

if (!opportunityId) throw new Error('Falta opportunityId. Body recibido: ' + JSON.stringify(body).substring(0, 300));
if (!newStageId)    throw new Error('Falta newStageId. Body recibido: ' + JSON.stringify(body).substring(0, 300));

return [{ json: { opportunityId, newStageId, locationId } }];

// Obtiene la oportunidad actual para leer sus custom fields existentes.
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const { opportunityId } = $input.first().json;
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let resp, data;
for (let i = 0; i < 4; i++) {
  resp = await fetch(`https://services.leadconnectorhq.com/opportunities/${opportunityId}`, {
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Version': '2021-07-28'
    }
  });
  if (resp.status === 429) { await sleep(Math.pow(2, i) * 1000); continue; }
  if (!resp.ok) throw new Error(`GET opportunity ${opportunityId} -> HTTP ${resp.status}`);
  data = await resp.json();
  break;
}

const opp = data.opportunity || data;
return [{ json: { opp, opportunityId: opp.id || opportunityId } }];

// Determina qué campos DATE actualizar según la etapa nueva.
// Lógica:
//   1. Cerrar etapas "abiertas" (tienen fecha_entrada pero no fecha_salida) que NO son la nueva etapa.
//   2. Abrir la nueva etapa si aún no tiene fecha_entrada.

const { opp, opportunityId } = $('GET Opportunity GHL').item.json;
const { newStageId } = $('Validar y Extraer Datos').item.json;

// Mapa stageId → IDs de custom fields GHL + columnas Postgres (carpeta Interno)
const STAGE_MAP = {
  'c9fd9604-1dc8-4816-a77f-3e750603963b': { name: 'Nuevo lead',      entradaId: 'aWaEuecxy4bmAqPvVqNJ', salidaId: 'MFMADsY77fpRy7myNODq', entradaCol: 'stage_nuevo_lead_entrada',      salidaCol: 'stage_nuevo_lead_salida'      },
  '7bdfe336-3bd6-48bd-a251-28228b782901': { name: 'Lead interesado',  entradaId: 'tcrI9JZqMnPxMh28vFfV', salidaId: 'TuzceQVUoZlU97HLaU2p', entradaCol: 'stage_lead_interesado_entrada', salidaCol: 'stage_lead_interesado_salida'  },
  '19225629-c452-4e4f-a4ae-90ad9e6aca9b': { name: 'Calendario',       entradaId: '3BbTXzm8zrYlGFrnBdB6', salidaId: 'Voof1iCLXQDqVGPhkww7', entradaCol: 'stage_calendario_entrada',      salidaCol: 'stage_calendario_salida'      },
  '5f8cc1c8-1d83-4d01-9441-6a5b7a155bc1': { name: 'Agendó Visita',   entradaId: 'GYEc6JI3we2JSCxrM3kc', salidaId: 'be4qNCxjt25ghFs7axR6', entradaCol: 'stage_agendo_visita_entrada',   salidaCol: 'stage_agendo_visita_salida'   },
  '5749d2b6-ab1d-4205-9744-bf5e78d9ca8a': { name: 'Hot',              entradaId: '0OeRKKkytLYf2vlXchbL', salidaId: 'Zne1flxBbYLa8gIyF1zf', entradaCol: 'stage_hot_entrada',             salidaCol: 'stage_hot_salida'             },
  '42cbfc36-1ef7-4788-a020-bf12ed1f9eb8': { name: 'Seguimiento',      entradaId: '2JouertsEonbaIyANlr1', salidaId: 'VtepsKumEVQpj8gNcpFe', entradaCol: 'stage_seguimiento_entrada',     salidaCol: 'stage_seguimiento_salida'     },
  '8429d63a-e58e-4c4b-bcbf-7bcffcc72c8a': { name: 'Cierre Ganado',    entradaId: 'EMQNXKc41d60L9Om1zuV', salidaId: 'w1tIloODf1Bf2W59zsCh', entradaCol: 'stage_cierre_ganado_entrada',   salidaCol: 'stage_cierre_ganado_salida'   },
  'bdc19de0-5025-4ebf-85e1-7fb5c1518d36': { name: 'Cierre Perdido',   entradaId: 'txHk9M6z4b65FJGWwm34', salidaId: 'eXNeJSvXSyCZRs9ZkeFS', entradaCol: 'stage_cierre_perdido_entrada',  salidaCol: 'stage_cierre_perdido_salida'  }
};

const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD

// Indexar valores actuales de custom fields
const customFields = opp.customFields || [];
const fieldValues = {};
for (const cf of customFields) {
  if (cf.id) fieldValues[cf.id] = cf.field_value || cf.value || null;
}

const ghlUpdates = [];   // Para el PUT a GHL
const pgUpdates  = [];   // Para el UPDATE en Postgres { col, val }

// 1. Cerrar etapas abiertas (entrada sin salida, y no es la etapa nueva)
for (const [stageId, stage] of Object.entries(STAGE_MAP)) {
  if (stageId === newStageId) continue;
  const hasEntrada = fieldValues[stage.entradaId];
  const hasSalida  = fieldValues[stage.salidaId];
  if (hasEntrada && !hasSalida) {
    ghlUpdates.push({ id: stage.salidaId, field_value: today });
    pgUpdates.push({ col: stage.salidaCol, val: today });
  }
}

// 2. Abrir la nueva etapa si no tiene fecha_entrada aún
const newStage = STAGE_MAP[newStageId];
if (newStage && !fieldValues[newStage.entradaId]) {
  ghlUpdates.push({ id: newStage.entradaId, field_value: today });
  pgUpdates.push({ col: newStage.entradaCol, val: today });
}

return [{ json: { opportunityId, newStageId, ghlUpdates, pgUpdates, today, hasUpdates: ghlUpdates.length > 0 } }];

// Actualiza los custom fields de la oportunidad en GHL.
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const { opportunityId, ghlUpdates, pgUpdates, newStageId, today } = $input.first().json;
const apiKey = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

const body = JSON.stringify({ customFields: ghlUpdates });

let resp;
for (let i = 0; i < 4; i++) {
  resp = await fetch(`https://services.leadconnectorhq.com/opportunities/${opportunityId}`, {
    method: 'PUT',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Version': '2021-07-28',
      'Content-Type': 'application/json'
    },
    body
  });
  if (resp.status === 429) { await sleep(Math.pow(2, i) * 1000); continue; }
  if (!resp.ok) {
    const err = await resp.text();
    throw new Error(`PUT opportunity ${opportunityId} -> HTTP ${resp.status}: ${err}`);
  }
  break;
}

return [{ json: { opportunityId, newStageId, ghlUpdates, pgUpdates, today, updatedFields: ghlUpdates.length } }];

// Construye el UPDATE SQL para dim_opportunities con las columnas de stage dates.
const { opportunityId, pgUpdates, newStageId, today, updatedFields } = $input.first().json;

if (!pgUpdates || pgUpdates.length === 0) {
  return [{ json: { sql: null, params: null, opportunityId, updatedFields } }];
}

// Construir SET clause dinámica
const setClauses = pgUpdates.map((u, i) => `${u.col} = $${i + 2}`);
const params = [opportunityId, ...pgUpdates.map(u => u.val)];

const sql = `UPDATE dim_opportunities
SET ${setClauses.join(',\n    ')}
WHERE opportunity_id = $1
  AND is_current = TRUE`;

return [{ json: { sql, params, opportunityId, newStageId, updatedFields } }];
